import swal from "sweetalert";
import {useState} from 'react';

const Mylogin = () =>{
  let[useremail, pickemail] = useState("");
  let[password, pickpassword] = useState("");


  const validation = () => {
    let status = true;

    // name check
    let uname = document.getElementById("uname").value;
    if (uname == "") {
    status = false;
      document.getElementById("nameerror").innerText =
        "Please fill name field ! ";
    } else {
      document.getElementById("nameerror").innerText = "";
    }

    // emailcheck
    let uemail = document.getElementById("uemail").value;
    if (uemail == "") {
    status = false;
      document.getElementById("emailerror").innerText =
        "Please fill email field ! ";
    } else {
      document.getElementById("emailerror").innerText = "";
    }


    // passwordcheck
    let upassword = document.getElementById("upassword").value;
    if (upassword == "") {
       status = false;
         document.getElementById("passworderror").innerText =
           "Please fill password field ! ";
       } else {
         document.getElementById("passworderror").innerText = "";
       }

       
       //sourcecheck
       let usource = document.getElementById("usource").value;
    if (usource == "") {
       status = false;
         document.getElementById("sourceerror").innerText =
           "Please fill source field ! ";
       } else {
         document.getElementById("sourceerror").innerText = "";
       }
   
       // citycheck
       let ucity = document.getElementById("ucity").value;
    if (ucity == "") {
       status = false;
         document.getElementById("cityerror").innerText =
           "Please fill city field ! ";
       } else {
         document.getElementById("cityerror").innerText = "";
       }

       
        // statecheck
        let ustate = document.getElementById("ustate").value;
    if (ustate == "") {
       status = false;
         document.getElementById("stateerror").innerText =
           "Please fill state field ! ";
       } else {
         document.getElementById("stateerror").innerText = "";
       }

    if (status) save();

  };

  
  const login = () =>{
     let url = "http://localhost:3333/account";
     let flag = 0;
     fetch(url)
     .then(response => response.json())
     .then(userinfo => {
        userinfo.map((acntdata, index) =>{
            if(acntdata.email === useremail && acntdata.password === password)
             {
                flag = 1;
                localStorage.setItem("fullname", acntdata.name);
                window.location.href="http://localhost:3000/#/"
              window.location.reload();// Reload the page(app.js) after login is success
             }
        })
        if(flag === 0)
        swal("Error", "invalid Or Not Exists", "warning");
     })
  }

 
  return(
     <div className="container mt-5">
        <div className="row">
            <div className="col-lg-3"></div>
            <div className="col-lg-6 w-50 border bg-secondary text-white p-5">
                <div className="border p-4 rounded shadow">
                    <h3 className="text-center"> {console.log("paritosh")} User Login </h3>
                    <div className="mb-4">
                        <label>Email id</label>
                        <input type="email"  className="form-control" value={useremail} onChange={obj=> pickemail(obj.target.value)}/> 
                    </div>

                    <div className="mb-3">
                        <label>Password</label>
                        <input type="password" className="form-control" value={password} onChange={obj=> pickpassword(obj.target.value)}/>
                    </div>

                    <div className="text-center">
                        <button className="btn btn-info" onClick={validation}>Login</button>
                    </div>
                </div>
            </div>
        </div>
     </div>
  )
}

export default Mylogin;
